namespace Apex.Modules.Accounting.ChartOfAccounts;
internal static class ChartOfAccountsEndpoints{internal static IEndpointRouteBuilder MapChartOfAccountsEndpoints(this IEndpointRouteBuilder app){var g=app.MapGroup("/api/v1/accounting/chart-of-accounts").WithTags("Accounting - Chart of Accounts");g.MapCreateAccountClassEndpoint().MapUpdateAccountClassEndpoint().MapArchiveAccountClassEndpoint().MapReactivateAccountClassEndpoint().MapCreateGeneralAccountEndpoint().MapUpdateGeneralAccountEndpoint().MapArchiveGeneralAccountEndpoint().MapReactivateGeneralAccountEndpoint().MapCreateSubsidiaryAccountEndpoint().MapUpdateSubsidiaryAccountEndpoint().MapArchiveSubsidiaryAccountEndpoint().MapReactivateSubsidiaryAccountEndpoint().MapGetAccountEndpoint().MapGetAccountTreeEndpoint().MapSearchAccountsEndpoint();return app;}}
